/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp). */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token t = in.readToken();
    if (t != null) {
      throw new ParseException("Extra token in input: " + t);
    }
    return result;
  }

  /** Parses:
    *   Exp ::= if Exp then Exp else Exp
    *         | let Def+ in Exp
    *         | map IdList to Exp
    *         | Term { BinOp Term }*   (left-associative)
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF) {
      in.readToken();
      return parseIf();
    } else if (t == Lexer.LET) {
      in.readToken();
      return parseLet();
    } else if (t == Lexer.MAP) {
      in.readToken();
      return parseMap();
    } else {
      return parseBinaryExp();
    }
  }

  /** Parses: if Exp then Exp else Exp
    * (the 'if' token has already been consumed)
    */
  private AST parseIf() {
    AST test = parseExp();
    Token t = in.readToken();
    if (t != Lexer.THEN) {
      throw new ParseException("Expected 'then' but got: " + t);
    }
    AST conseq = parseExp();
    t = in.readToken();
    if (t != Lexer.ELSE) {
      throw new ParseException("Expected 'else' but got: " + t);
    }
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let Def+ in Exp
    * (the 'let' token has already been consumed)
    */
  private AST parseLet() {
    List<Def> defs = new ArrayList<Def>();
    while (true) {
      Token t = in.peek();
      if (t == null) {
        throw new ParseException("Unexpected end of input in let expression");
      }
      if (t == Lexer.IN) break;
      defs.add(parseDef());
    }
    if (defs.isEmpty()) {
      throw new ParseException("let expression requires at least one definition");
    }
    in.readToken();  // consume 'in'
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: Id := Exp ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable)) {
      throw new ParseException("Expected variable in definition but got: " + t);
    }
    Variable var = (Variable) t;
    t = in.readToken();
    if (t != Lexer.BIND) {
      throw new ParseException("Expected ':=' but got: " + t);
    }
    AST rhs = parseExp();
    t = in.readToken();
    if (t != SemiColon.ONLY) {
      throw new ParseException("Expected ';' but got: " + t);
    }
    return new Def(var, rhs);
  }

  /** Parses: map IdList to Exp
    * (the 'map' token has already been consumed)
    */
  private AST parseMap() {
    Variable[] vars = parseIdList();
    Token t = in.readToken();
    if (t != Lexer.TO) {
      throw new ParseException("Expected 'to' but got: " + t);
    }
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: IdList ::= { PropIdList }
    * PropIdList ::= Id { , Id }*
    */
  private Variable[] parseIdList() {
    Token t = in.peek();
    if (t == Lexer.TO) {
      return new Variable[0];
    }
    List<Variable> vars = new ArrayList<Variable>();
    t = in.readToken();
    if (!(t instanceof Variable)) {
      throw new ParseException("Expected variable in id list but got: " + t);
    }
    vars.add((Variable) t);
    while (in.peek() == Comma.ONLY) {
      in.readToken();  // consume ','
      t = in.readToken();
      if (!(t instanceof Variable)) {
        throw new ParseException("Expected variable after ',' but got: " + t);
      }
      vars.add((Variable) t);
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: BinaryExp ::= Term { BinOp Term }*  (left-associative) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (true) {
      Token t = in.peek();
      if (!(t instanceof OpToken)) break;
      OpToken op = (OpToken) t;
      if (!op.isBinOp()) break;
      in.readToken();  // consume binop
      AST right = parseTerm();
      left = new BinOpApp(op.toBinOp(), left, right);
    }
    return left;
  }

  /** Parses:
    *   Term ::= Unop Term
    *          | Factor { ( ExpList ) }
    *          | Empty
    *          | Int
    *          | Bool
    */
  private AST parseTerm() {
    Token t = in.peek();

    if (t instanceof OpToken) {
      OpToken op = (OpToken) t;
      if (op.isUnOp()) {
        in.readToken();  // consume unop
        AST arg = parseTerm();
        return new UnOpApp(op.toUnOp(), arg);
      }
      throw new ParseException("Unexpected operator (not a unary op): " + t);
    }

    if (t instanceof EmptyConstant) {
      in.readToken();
      return (EmptyConstant) t;
    }

    if (t instanceof IntConstant) {
      in.readToken();
      return (IntConstant) t;
    }

    if (t instanceof BoolConstant) {
      in.readToken();
      return (BoolConstant) t;
    }

    // Factor { ( ExpList ) }
    AST factor = parseFactor();
    if (in.peek() == LeftParen.ONLY) {
      in.readToken();  // consume '('
      AST[] args = parseExpList();
      Token rp = in.readToken();
      if (rp != RightParen.ONLY) {
        throw new ParseException("Expected ')' but got: " + rp);
      }
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: Factor ::= ( Exp ) | Prim | Id */
  private AST parseFactor() {
    Token t = in.readToken();

    if (t == null) {
      throw new ParseException("Unexpected end of input");
    }

    if (t == LeftParen.ONLY) {
      AST exp = parseExp();
      Token rp = in.readToken();
      if (rp != RightParen.ONLY) {
        throw new ParseException("Expected ')' but got: " + rp);
      }
      return exp;
    }

    if (t instanceof PrimFun) {
      return (PrimFun) t;
    }

    if (t instanceof Variable) {
      return (Variable) t;
    }

    throw new ParseException("Unexpected token: " + t);
  }

  /** Parses: ExpList ::= { PropExpList }
    * PropExpList ::= Exp { , Exp }*
    */
  private AST[] parseExpList() {
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];
    }
    List<AST> exps = new ArrayList<AST>();
    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken();  // consume ','
      exps.add(parseExp());
    }
    return exps.toArray(new AST[0]);
  }
}

